import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";

import { buildActiveCatalog } from "../src/data/pipeline.js";

const DEFAULT_RAW_PATH = "data/raw-products.json";
const DEFAULT_ACTIVE_PATH = "data/active-products.json";
const DEFAULT_MODULE_PATH = "src/lib/products.js";

function readJson(path) {
  return JSON.parse(readFileSync(path, "utf8"));
}

function writeJson(path, data) {
  writeFileSync(path, `${JSON.stringify(data, null, 2)}\n`);
}

function toBrowserModule(products) {
  return [
    "/* Generated by scripts/update-products.js. Edit data/raw-products.json instead. */",
    `export const SAMPLE_PRODUCTS = ${JSON.stringify(products, null, 2)};`,
    "",
  ].join("\n");
}

export function updateProductFiles({
  rawPath = DEFAULT_RAW_PATH,
  activePath = DEFAULT_ACTIVE_PATH,
  modulePath = DEFAULT_MODULE_PATH,
  today,
} = {}) {
  const rawProducts = readJson(rawPath);
  const catalog = buildActiveCatalog(rawProducts, { today });

  writeJson(activePath, {
    metadata: catalog.metadata,
    products: catalog.activeProducts,
    rejectedProducts: catalog.rejectedProducts,
  });
  writeFileSync(modulePath, toBrowserModule(catalog.activeProducts));

  return {
    activeCount: catalog.activeProducts.length,
    rejectedCount: catalog.rejectedProducts.length,
    sourceCount: rawProducts.length,
  };
}

function main() {
  const summary = updateProductFiles();
  console.log(
    `Updated product catalog: ${summary.activeCount} active, ${summary.rejectedCount} rejected, ${summary.sourceCount} raw`,
  );
}

if (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {
  main();
}
